
CREATE TABLE "USERS" (
    "USER_ID" NUMBER GENERATED BY DEFAULT AS IDENTITY,
    "NAME" VARCHAR2(100) NOT NULL,
    "EMAIL" VARCHAR2(150) NOT NULL,
    "PASSWORD" VARCHAR2(255) NOT NULL,
    "CREATED_AT" TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    "IS_GUEST" NUMBER(1,0) DEFAULT 0,
    PRIMARY KEY ("USER_ID"),
    UNIQUE ("EMAIL")
);

CREATE TABLE "REGIONS" (
    "REGION_ID" NUMBER GENERATED BY DEFAULT AS IDENTITY,
    "REGION_NAME" VARCHAR2(100) NOT NULL,
    "REGION_DESCRIPTION" CLOB,
    PRIMARY KEY ("REGION_ID")
);

CREATE TABLE "PROVINCES" (
    "PROVINCE_ID" NUMBER,
    "REGION_ID" NUMBER NOT NULL,
    "PROVINCE_NAME" VARCHAR2(100) NOT NULL,
    PRIMARY KEY ("PROVINCE_ID"),
    CONSTRAINT "FK_PROVINCES_REGIONS"
        FOREIGN KEY ("REGION_ID")
        REFERENCES "REGIONS" ("REGION_ID")
);

CREATE TABLE "PLACE_TYPES" (
    "TYPE_ID" NUMBER GENERATED BY DEFAULT AS IDENTITY,
    "TYPE_NAME" VARCHAR2(100) NOT NULL,
    PRIMARY KEY ("TYPE_ID")
);

CREATE TABLE "PLACES" (
    "PLACE_ID" NUMBER GENERATED BY DEFAULT AS IDENTITY,
    "PLACE_NAME" VARCHAR2(150) NOT NULL,
    "DESCRIPTION" CLOB,
    "TYPE_ID" NUMBER NOT NULL,
    "PROVINCE_ID" NUMBER,
    PRIMARY KEY ("PLACE_ID"),

    CONSTRAINT "FK_PLACE_TYPE"
        FOREIGN KEY ("TYPE_ID")
        REFERENCES "PLACE_TYPES" ("TYPE_ID")
        ON DELETE CASCADE,

    CONSTRAINT "FK_PLACE_PROVINCE"
        FOREIGN KEY ("PROVINCE_ID")
        REFERENCES "PROVINCES" ("PROVINCE_ID")
);

CREATE TABLE "LOCATION" (
    "LOCATION_ID" NUMBER,
    "PLACE_ID" NUMBER,
    "LATITUDE" NUMBER(9,6),
    "LONGITUDE" NUMBER(9,6),
    PRIMARY KEY ("LOCATION_ID"),
    UNIQUE ("PLACE_ID"),

    CONSTRAINT "FK_LOCATION_PLACE"
        FOREIGN KEY ("PLACE_ID")
        REFERENCES "PLACES" ("PLACE_ID")
);
 CREATE TABLE "MEDIA" (
    "MEDIA_ID" NUMBER GENERATED BY DEFAULT AS IDENTITY,
    "PLACE_ID" NUMBER NOT NULL,
    "MEDIA_URL" VARCHAR2(300) NOT NULL,
    "MEDIA_DESCRIPTION" CLOB,
    "MEDIA_TYPE" VARCHAR2(10),
    PRIMARY KEY ("MEDIA_ID"),

    CHECK ("MEDIA_TYPE" IN ('image','video')),

    CONSTRAINT "FK_IMAGE_PLACE"
        FOREIGN KEY ("PLACE_ID")
        REFERENCES "PLACES" ("PLACE_ID")
        ON DELETE CASCADE
);

CREATE TABLE "EVENTS" (
    EVENT_ID NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    PLACE_ID NUMBER NOT NULL,
    EVENT_NAME VARCHAR2(150) NOT NULL,
    EVENT_DESCRIPTION CLOB,
    START_DATE DATE,
    END_DATE DATE,
    TICKET_PRICE NUMBER(8,2),
    CONSTRAINT FK_EVENT_PLACE
        FOREIGN KEY (PLACE_ID)
        REFERENCES PLACES(PLACE_ID)
        ON DELETE CASCADE
);

CREATE TABLE "REVIEWS" (
    REVIEW_ID NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    USER_ID NUMBER NOT NULL,
    PLACE_ID NUMBER NOT NULL,
    RATING NUMBER(1,0),
    REVIEW_COMMENT CLOB,
    CREATED_AT TIMESTAMP(6) DEFAULT CURRENT_TIMESTAMP,
    CHECK (RATING BETWEEN 1 AND 5),
    CONSTRAINT FK_REVIEW_USER
        FOREIGN KEY (USER_ID)
        REFERENCES USERS(USER_ID)
        ON DELETE CASCADE,
    CONSTRAINT FK_REVIEW_PLACE
        FOREIGN KEY (PLACE_ID)
        REFERENCES PLACES(PLACE_ID)
        ON DELETE CASCADE
);
